counts2 = {
  const c = {};
  for (const cat of categories2) c[cat] = 0;
  for (const r of results2) c[r] = (c[r] || 0) + 1;
  return c;
}

chartData2 = categories2.flatMap(cat =&gt; {
  const observed = totalCount2 &gt; 0 ? counts2[cat] / totalCount2 : 0;
  return [
    {category: String(cat), type: "observed", probability: observed},
    {category: String(cat), type: "theoretical", probability: theoreticalProb2}
  ];
})

