    const pad = 8;
    const symW = 24;
    const rowH = 18;
    const textW = Math.max(...items.map(d =&gt; d.label.length * 7.2));
    const boxW = pad * 2 + symW + textW;
    const boxH = pad * 2 + items.length * rowH;
    const x0 = innerW - boxW - 4;
    const y0 = innerH - boxH - 4;
    legendG.append("rect")
