  function fitRegression() {
    const {X: Xraw} = mapOneFeature(ptsX, degree);
    const {X, mu, sigma} = zscoreNormalize(Xraw);
    const {w, b} = solveLinear(X, ptsY, lambda_);
    wFit = w;
    bFit = b;
    muFit = mu;
    sigmaFit = sigma;
    const xs = d3.range(xLim[0], xLim[1] + 0.01, (xLim[1] - xLim[0]) / 80);
    const {X: Xm} = mapOneFeature(xs, degree);
    const Xms = scaleRows(Xm, mu, sigma);
    fitLine = xs.map((x, i) =&gt; {
      let pred = b;
      for (let j = 0; j &lt; w.length; j++) pred += w[j] * Xms[i][j];
      return {x, y: pred};
    });
  }

  function fitCategorical() {
    const {X: Xraw} = mapFeature(ptsX, ptsX1, degree);
    const {X, mu, sigma} = zscoreNormalize(Xraw);
    const {w, b} = logisticGD(X, ptsY, 0.3, 3000, lambda_);
    wFit = w;
    bFit = b;
    muFit = mu;
    sigmaFit = sigma;
    // Build decision boundary using marching squares (no d3-contour needed)
    const nx = 100, ny = 100;
    const dx = (xLim[1] - xLim[0]) / nx;
    const dy = (yLim[1] - yLim[0]) / ny;
    // Compute grid of predictions
    const grid = [];
    for (let iy = 0; iy &lt;= ny; iy++) {
      const row = [];
      const x1v = yLim[0] + iy * dy;
      for (let ix = 0; ix &lt;= nx; ix++) {
        const x0v = xLim[0] + ix * dx;
        const {X: Xm} = mapFeature([x0v], [x1v], degree);
        const Xms = scaleRows(Xm, mu, sigma);
        const p = predictLogistic(Xms, w, b)[0];
        row.push(p);
      }
      grid.push(row);
    }
    // March through grid cells, collect line segments where p crosses 0.5
    const {xScale, yScale} = makeScales();
    const segments = [];
    for (let iy = 0; iy &lt; ny; iy++) {
      for (let ix = 0; ix &lt; nx; ix++) {
        const tl = grid[iy][ix], tr = grid[iy][ix+1];
        const bl = grid[iy+1][ix], br = grid[iy+1][ix+1];
        const x0 = xLim[0] + ix * dx, x1 = x0 + dx;
        const y0 = yLim[0] + iy * dy, y1 = y0 + dy;
        const pts = [];
        if ((tl - 0.5) * (tr - 0.5) &lt; 0) { const t = (0.5 - tl)/(tr - tl); pts.push([x0 + t*dx, y0]); }
        if ((tr - 0.5) * (br - 0.5) &lt; 0) { const t = (0.5 - tr)/(br - tr); pts.push([x1, y0 + t*dy]); }
        if ((bl - 0.5) * (br - 0.5) &lt; 0) { const t = (0.5 - bl)/(br - bl); pts.push([x0 + t*dx, y1]); }
        if ((tl - 0.5) * (bl - 0.5) &lt; 0) { const t = (0.5 - tl)/(bl - tl); pts.push([x0, y0 + t*dy]); }
        if (pts.length &gt;= 2) {
          segments.push([[xScale(pts[0][0]), yScale(pts[0][1])], [xScale(pts[1][0]), yScale(pts[1][1])]]);
          if (pts.length === 4) {
            segments.push([[xScale(pts[2][0]), yScale(pts[2][1])], [xScale(pts[3][0]), yScale(pts[3][1])]]);
          }
        }
      }
    }
    contourPaths = segments;
  }

