      ptsY = [...ptsY, yCls];
    } else {
      ptsX = [...ptsX, xVal];
      ptsY = [...ptsY, yVal];
    }
    fitLine = null;
    contourPaths = [];
    wFit = null;
    redraw();
  });

  redraw();
  return container;
