  function gradientDescent(x, y, w0, b0, alpha, numIters) {
    let wv = w0, bv = b0;
    const m = x.length;
    for (let t = 0; t &lt; numIters; t++) {
      let dj_dw = 0, dj_db = 0;
      for (let i = 0; i &lt; m; i++) {
        const err = wv * x[i] + bv - y[i];
        dj_dw += err * x[i];
        dj_db += err;
      }
      dj_dw /= m;
      dj_db /= m;
      wv -= alpha * dj_dw;
      bv -= alpha * dj_db;
    }
    return {w: wv, b: bv};
  }

