    const x0 = xMin;
    const x1 = xMax;
    const y0 = w * x0 + b;
    const y1 = w * x1 + b;
    lineG.append("line")
      .attr("x1", xScale(x0)).attr("y1", yScale(y0))
      .attr("x2", xScale(x1)).attr("y2", yScale(y1))
      .attr("stroke", dlblue).attr("stroke-width", 2.5);
    labelG.selectAll("*").remove();
    labelG.append("text")
      .attr("x", innerW - 8).attr("y", innerH - 8)
      .attr("text-anchor", "end").attr("font-size", 11).attr("fill", dlblue)
      .text(lineLabel);
  }

  function drawThreshold() {
    threshG.selectAll("*").remove();
    if (!showThresh || Math.abs(w) &lt; 1e-8) return;
    const xCut = (0.5 - b) / w;
    threshG.append("rect").attr("x", xScale(xMin)).attr("y", 0).attr("width", xScale(xCut) - xScale(xMin)).attr("height", innerH).attr("fill", dlblue).attr("opacity", 0.12);
    threshG.append("rect").attr("x", xScale(xCut)).attr("y", 0).attr("width", xScale(xMax) - xScale(xCut)).attr("height", innerH).attr("fill", dldarkred).attr("opacity", 0.12);
    threshG.append("line").attr("x1", xScale(xCut)).attr("x2", xScale(xCut)).attr("y1", 0).attr("y2", innerH).attr("stroke", "#888").attr("stroke-dasharray", "4,3");
    threshG.append("text").attr("x", xScale(xCut) + 8).attr("y", yScale(0.55)).attr("font-size", 11).attr("fill", dldarkred).text("Malignant");
    threshG.append("text").attr("x", xScale(xCut) - 8).attr("y", yScale(0.55)).attr("text-anchor", "end").attr("font-size", 11).attr("fill", dlblue).text("Benign");
  }

  function updateStatus(msg) {
    container.querySelector("#lr-status").textContent = msg;
  }

  function redraw() {
    drawPoints();
    drawLine();
    drawThreshold();
    if (lineLabel && Math.abs(w) &gt; 1e-8) {
      const f3 = w * 3 + b;
      updateStatus(`Model: ${lineLabel}.  f(3) ≈ ${f3.toFixed(2)}.  Threshold cutoff x ≈ ${((0.5 - b) / w).toFixed(2)}.`);
    } else if (!lineLabel) {
      updateStatus("Click Run Linear Regression to fit a line to the current points.");
    }
  }

  drawGrid();
  redraw();

  container.querySelector("#run-lr").addEventListener("click", async () =&gt; {
    const btn = container.querySelector("#run-lr");
    btn.disabled = true;
    btn.textContent = "Running...";
    const steps = [1, 1, 1, 1, 1, 2, 4, 8, 16, 32, 64, 128, 256];
    for (const it of steps) {
      ({w, b} = gradientDescent(ptsX, ptsY, w, b, 0.01, it));
      lineLabel = `y = ${w.toFixed(2)}x + (${b.toFixed(2)})`;
      redraw();
      await new Promise(r =&gt; setTimeout(r, 280));
    }
    btn.disabled = false;
    btn.textContent = "Run Linear Regression";
  });

  container.querySelector("#thresh-toggle").addEventListener("change", (ev) =&gt; {
    showThresh = ev.target.checked;
    redraw();
  });

  container.querySelector("#reset-data").addEventListener("click", () =&gt; {
    ptsX = initX.slice();
    ptsY = initY.slice();
    w = 0;
    b = 0;
    lineLabel = "";
    showThresh = false;
    container.querySelector("#thresh-toggle").checked = false;
    redraw();
  });

  svg.on("click", (event) =&gt; {
    const [mx, my] = d3.pointer(event, g.node());
    if (mx &lt; 0 || mx &gt; innerW || my &lt; 0 || my &gt; innerH) return;
    const xVal = xScale.invert(mx);
    const yVal = yScale.invert(my) &gt; 0.5 ? 1 : 0;
    ptsX = [...ptsX, xVal];
    ptsY = [...ptsY, yVal];
    redraw();
  });

  return container;
}







